import React, { useMemo } from "react";

const toF = (c) => (c == null ? null : (c * 9) / 5 + 32);

function safeLabel(w) {
  // w can be string | array | object | number | undefined
  if (w == null) return "â€”";
  if (typeof w === "string" || typeof w === "number") return String(w);
  if (Array.isArray(w)) {
    const first = w[0];
    if (typeof first === "string") return first;
    if (first && typeof first === "object") return first.description || first.main || "â€”";
    return "â€”";
  }
  if (typeof w === "object") return w.description || w.main || "â€”";
  return String(w);
}

function DayRow({ dt, label, hi, lo }) {
  const day = useMemo(
    () => new Date((dt ?? Math.floor(Date.now() / 1000)) * 1000).toLocaleDateString(undefined, { weekday: "short" }),
    [dt]
  );
  return (
    <div className="flex items-center justify-between rounded-2xl px-3 py-2 bg-black/30 backdrop-blur">
      <div className="w-20">{day}</div>
      <div className="flex-1 px-2 opacity-90 capitalize">{label}</div>
      <div className="w-28 text-right tabular-nums">
        {hi ?? "--"}Â° / {lo ?? "--"}Â°
      </div>
    </div>
  );
}

export default function Forecast({ hourly = [], daily = [], daily16 = [], unit = "metric" }) {
  const days = Array.isArray(daily) ? daily.slice(0, 7) : [];

  return (
    <div className="space-y-3">
      {/* 7-day */}
      {days.length === 0 ? (
        <div className="rounded-2xl px-3 py-2 bg-black/25">No forecast data.</div>
      ) : (
        days.map((d, i) => {
          const hiC = d?.temp?.max ?? d?.max ?? null;
          const loC = d?.temp?.min ?? d?.min ?? null;
          const hi = unit === "imperial" ? (hiC == null ? null : Math.round(toF(hiC))) : (hiC == null ? null : Math.round(hiC));
          const lo = unit === "imperial" ? (loC == null ? null : Math.round(toF(loC))) : (loC == null ? null : Math.round(loC));
          const label = safeLabel(d?.weather);
          return <DayRow key={i} dt={d?.dt} label={label} hi={hi} lo={lo} />;
        })
      )}

      {/* Optionally render extended 16-day if provided */}
      {Array.isArray(daily16) && daily16.length > 7 && (
        <details className="rounded-2xl bg-black/20">
          <summary className="cursor-pointer px-3 py-2">Extended forecast (days 8â€“16)</summary>
          <div className="p-3 space-y-2">
            {daily16.slice(7, 16).map((d, i) => {
              const hiC = d?.temp?.max ?? d?.max ?? null;
              const loC = d?.temp?.min ?? d?.min ?? null;
              const hi = unit === "imperial" ? (hiC == null ? null : Math.round(toF(hiC))) : (hiC == null ? null : Math.round(hiC));
              const lo = unit === "imperial" ? (loC == null ? null : Math.round(toF(loC))) : (loC == null ? null : Math.round(loC));
              const label = safeLabel(d?.weather);
              return <DayRow key={`ext-${i}`} dt={d?.dt} label={label} hi={hi} lo={lo} />;
            })}
          </div>
        </details>
      )}
    </div>
  );
}
